sql:
SELECT AVG(rating) AS average_user_rating
FROM user_feedback
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM bets
);

SELECT game_type_name
FROM game_types
WHERE game_type_name = 'Regular Season';

external_knowledge:
- 'Top players in the spotlight' refers to players who had the highest combined points, rebounds, and assists in a game; 
- 'stole the show' means having the highest combined points, rebounds, and assists among all players in a game; 
- 'covered the spread' means the Timberwolves won by more than the expected margin; 
- 'total score went over the expected total' means the total points scored in the game exceeded the predicted total points.

sql:
SELECT predicted_winner, AVG(confidence_level) AS average_confidence
FROM game_predictions
GROUP BY predicted_winner;

SELECT game_id, predicted_winner
FROM game_predictions
WHERE confidence_level > 0.8;
